// SLOW VERSION: O(n²) — nested loops
function findDuplicatesSlow(ids: number[]): number[] {
  const duplicates: number[] = [];
  for (let i = 0; i < ids.length; i++) {
    for (let j = i + 1; j < ids.length; j++) {
      if (ids[i] === ids[j] && !duplicates.includes(ids[i])) {
        duplicates.push(ids[i]);
      }
    }
  }
  return duplicates;
}
// FAST VERSION: O(n) — single pass with a Set
function findDuplicatesFast(ids: number[]): number[] {
  const seen: Set<number> = new Set();
  const duplicates: Set<number> = new Set();
  for (const id of ids) {
    if (seen.has(id)) {
      duplicates.add(id);
    } else {
      seen.add(id);
    }
  }
  return [...duplicates];
}
// With 10,000 items, the slow version takes ~1000x longer
// Always prefer O(n) Set/Map over O(n²) nested loops for lookups
